import React, { useEffect, useState } from "react";
import "./Home.css";
import gsap from "gsap";

const Login = () => {
  
  
  //States
  const [email,setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  useEffect(() => {
    console.log('Email updated:', email);
  }, [email]); 
   // Handle form submission
   const handleSubmit = async (e) => {
    e.preventDefault(); // Prevent the form from refreshing the page
    setError(null); // Clear any previous errors

    try {
      // Make the API call
      const response = await axios.post("https://bidwheels-api-env.eba-ts5rcstj.us-east-1.elasticbeanstalk.com/login", {
        email,
        password,
      });

      // Check if the response indicates success
      if (response.ok) {
        setIsLoggedIn(true); // Set login state to true
        console.log("Login successful");
      } else {
        setError("Invalid email or password");
      }
    } catch (err) {
      setError("Something went wrong. Please try again.");
    }
  };

  // If logged in, display a success message
  if (isLoggedIn) {
    
    return <div>Welcome! You are successfully logged in.</div>;
  }

  useEffect(() => {
    // GSAP animation for the logo
    gsap.fromTo(
        ".logo",
        { opacity: 0, scale: 0.5, y: -50 },
        { opacity: 1, scale: 1, y: 0, duration: 1.5, ease: "bounce.out" }
    );
}, []);

    return (
        <div className="login-container">
            <div className="login-left">
                <div className="logo">TRUXGO</div>
            </div>
            <div className="login-right">
                <div className="login-form">
                    <h2>Log In to your account</h2>
                    <form onSubmit={handleSubmit}>
                        <label>Email</label>
                        <input
                        type="email" 
                        placeholder="Enter your email"
                        value={email} //Binding value into state
                        onChange={(e) => setEmail(e.target.value)}
                        required />
                        <label>Password</label>
                        <input 
                        type="password" 
                        placeholder="Enter your password" 
                        value={password} // Bind input to state
                        onChange={(e) => setPassword(e.target.value)}
                        required />
                        <a href="/forgot-password" className="forgot-password">
                            Forgot your password?
                        </a>
                        <button type="submit">Log In</button>
                    </form>
                </div>
            </div>
        </div>
    );
};

export default Login;
